import {
  AppVersionApiResponse,
  AppVersionListApiResponse,
  SubmitAppVersionRequest,
  UpdateAppVersionRequest,
} from '../models/api/app-store-api.models';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Injectable, inject } from '@angular/core';
import { Observable, map } from 'rxjs';

import { ApiUrlService } from '../../../core/services/api-url.service';
import { AppVersion } from '../models/app-store.models';
import { isDefined } from '../../../shared/utils';
import { mapAppVersionFromApi } from '../models/api/app-store-api.mappers';

@Injectable({ providedIn: 'root' })
export class AppVersionService {
  private readonly http = inject(HttpClient);
  private readonly apiUrlService = inject(ApiUrlService);
  private readonly baseUrl = `${this.apiUrlService.getCurrentApiUrl()}/telemetrystore`;

  submitVersion(
    appId: string,
    request: SubmitAppVersionRequest,
  ): Observable<AppVersion> {
    return this.http
      .post<AppVersionApiResponse>(
        `${this.baseUrl}/apps/${appId}/versions`,
        request,
      )
      .pipe(map(mapAppVersionFromApi));
  }

  updateVersion(
    appId: string,
    versionId: string,
    request: UpdateAppVersionRequest,
  ): Observable<AppVersion> {
    return this.http
      .put<AppVersionApiResponse>(
        `${this.baseUrl}/apps/${appId}/versions/${versionId}`,
        request,
      )
      .pipe(map(mapAppVersionFromApi));
  }

  getVersions(appId: string): Observable<AppVersion[]> {
    return this.http
      .get<AppVersionListApiResponse>(`${this.baseUrl}/apps/${appId}/versions`)
      .pipe(map((r) => r.items.map(mapAppVersionFromApi)));
  }

  getVersion(appId: string, version: string): Observable<AppVersion> {
    return this.http
      .get<AppVersionApiResponse>(
        `${this.baseUrl}/apps/${appId}/versions/${version}`,
      )
      .pipe(map(mapAppVersionFromApi));
  }

  getAllVersions(
    params: { status?: string; offset?: number; limit?: number } = {},
  ): Observable<AppVersion[]> {
    let httpParams = new HttpParams();
    if (isDefined(params.status))
      httpParams = httpParams.set('status', params.status);
    if (params.offset !== undefined)
      httpParams = httpParams.set('offset', params.offset.toString());
    if (params.limit !== undefined)
      httpParams = httpParams.set('limit', params.limit.toString());

    return this.http
      .get<AppVersionListApiResponse>(`${this.baseUrl}/versions`, {
        params: httpParams,
      })
      .pipe(map((r) => r.items.map(mapAppVersionFromApi)));
  }
}
